def _table_cell(value: str) -> str:
    text = _brief_text(value).replace("|", "\\|")
    return text or "not recorded"


def _truncate(text: str, max_length: int) -> str:
    if len(text) <= max_length:
        return text
    return text[: max_length - 3].rstrip() + "..."


def _strip_terminal_period(text: str) -> str:
    return _brief_text(text).rstrip(".")


def _evidence_reference_summary(evidence_ids: list[Any], evidence_by_id: dict[str, dict[str, Any]]) -> str:
    refs: list[str] = []
    for evidence_id in evidence_ids:
        item = evidence_by_id.get(evidence_id)
        if not item:
            continue
        path = _brief_text(item.get("path"))
        locator = item.get("locator")
        locator_value = ""
        if isinstance(locator, dict):
            locator_value = _brief_text(locator.get("value"))
        ref = path
        if locator_value:
            ref = f"{ref} ({locator_value})"
        if ref:
            refs.append(ref)
    return ", ".join(_dedupe_brief_items(refs[:4]))


def _dedupe_brief_items(items: list[str]) -> list[str]:
    seen: set[str] = set()
    deduped: list[str] = []
    for item in items:
        text = _brief_text(item)

if not text:
            continue
        key = text.lower()
        if key in seen:
            continue
        seen.add(key)
        deduped.append(text)
    return deduped


def _list_text(values: list[str]) -> str:
    items = [value for value in values if value]
    if not items:
        return "not recorded"
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return f"{', '.join(items[:-1])}, and {items[-1]}"

def _ensure_chronology_artifact(
    artifact_inventory: dict[str, Any],
    repo_inventory: dict[str, Any],
    artifacts: list[dict[str, Any]],
    run_dir: Path,
) -> dict[str, Any]:
    artifact_records = artifact_inventory.setdefault("artifacts", [])
    if not isinstance(artifact_records, list):
        artifact_records = []
        artifact_inventory["artifacts"] = artifact_records

    chronology_artifact = {
        "artifact_id": CHRONOLOGY_ARTIFACT_ID,
        "repo_id": _inventory_anchor_repo_id(repo_inventory, artifacts),
        "path": CHRONOLOGY_PATH,
        "artifact_type": CHRONOLOGY_TYPE,
        "size_bytes": _file_size(run_dir / CHRONOLOGY_PATH),
        "size_estimate": "small",
        "likely_signal_value": "medium",
        "notes": "Synthetic run-boundary artifact used to anchor bounded chronology-derived cadence evidence.",
    }
    for index, artifact in enumerate(artifact_records):
        if isinstance(artifact, dict) and artifact.get("artifact_id") == CHRONOLOGY_ARTIFACT_ID:
            artifact_records[index] = chronology_artifact
            return chronology_artifact
    artifact_records.append(chronology_artifact)
    return chronology_artifact


