    result: ValidationResult,
) -> None:
    for claim in claims:
        _validate_repo_artifact_reference("Claim", claim.get("claim_id"), claim, boundary, result)
        for evidence_id in claim.get("evidence_ids", []) or []:
            if evidence_id not in ids["evidence"]:
